const getDailyMessage = (dateStr: string, count: number) => {
    // Hash based on date string to ensure consistent message for a specific date
    let hash = 0;
    for (let i = 0; i < dateStr.length; i++) {
        hash = ((hash << 5) - hash) + dateStr.charCodeAt(i);
        hash |= 0;
    }
    const absHash = Math.abs(hash);

    let category: string[] = MOTIVATIONAL_MESSAGES.zero;
    if (count === 10) category = MOTIVATIONAL_MESSAGES.perfect;
    else if (count >= 7) category = MOTIVATIONAL_MESSAGES.high;
    else if (count >= 4) category = MOTIVATIONAL_MESSAGES.medium;
    else if (count >= 1) category = MOTIVATIONAL_MESSAGES.low;

    return category[absHash % category.length];
};

const getMessageStyle = (count: number) => {
    if (count === 10) return 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-300';
    if (count >= 7) return 'bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300';
    if (count >= 4) return 'bg-orange-100 text-orange-800 dark:bg-orange-900/40 dark:text-orange-300';
    if (count >= 1) return 'bg-red-100 text-red-800 dark:bg-red-900/40 dark:text-red-300';
    return 'bg-slate-100 text-slate-500 dark:bg-slate-800 dark:text-slate-500';
};

const getMonthColor = (monthIndex: number, count: number) => {
    if (count === 0) return 'bg-slate-100 dark:bg-slate-800';
    const palette = MONTH_PALETTES[monthIndex].styles;
    if (count <= 3) return palette[0];
    if (count <= 6) return palette[1];
    if (count <= 9) return palette[2];
    return palette[3]; // Perfect 10
};

const getScoreColor = (count: number, isBg = true) => {
    if (count === 10) return isBg ? 'bg-emerald-500' : 'text-emerald-500';
    if (count >= 6) return isBg ? 'bg-blue-500' : 'text-blue-500';
    if (count >= 3) return isBg ? 'bg-orange-500' : 'text-orange-500';
    // 0-2 Range is Red
    return isBg ? 'bg-red-500' : 'text-red-500';
};

const getPercentageColor = (percentage: number) => {
    if (percentage === 100) return 'bg-emerald-500';
    if (percentage >= 80) return 'bg-cyan-500';
    if (percentage >= 60) return 'bg-blue-500';
    if (percentage >= 40) return 'bg-yellow-500';
    if (percentage >= 20) return 'bg-orange-500';
    return 'bg-red-500';
};

