                                        <div className="w-full space-y-1 mt-auto">
                                            <div className="w-full bg-slate-100 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                                                <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                            </div>
                                            <div className="text-[10px] font-bold text-slate-400 text-right">{count}/10</div>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    </>
                )}

                {calendarView === 'week' && (
                    <div className="overflow-x-auto">
                        <div className="min-w-[800px]">
                            <div className="grid grid-cols-[200px_repeat(7,1fr)] border-b border-slate-200 dark:border-slate-700">
                                <div className="p-4 font-bold text-slate-400 uppercase text-xs tracking-wider flex items-center bg-slate-50 dark:bg-slate-900/50">Habit (Default)</div>
                                {eachDayOfInterval({
                                    start: startOfWeek(currentDate),
                                    end: endOfWeek(currentDate)
                                }).map(day => (
                                    <button 
                                        key={day.toString()} 
                                        onClick={() => onSelectDate(format(day, 'yyyy-MM-dd'))}
                                        className={`p-4 text-center border-l border-slate-100 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-800/80 transition-colors group ${isToday(day) ? 'bg-indigo-50 dark:bg-indigo-900/20' : ''}`}
                                    >
                                        <div className="text-xs font-bold text-slate-500 uppercase group-hover:text-indigo-600 dark:group-hover:text-indigo-400">{format(day, 'EEE')}</div>
                                        <div className={`text-lg font-bold mt-1 group-hover:scale-110 transition-transform ${isToday(day) ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{format(day, 'd')}</div>
                                        <div className="text-[10px] text-slate-400 mt-1 opacity-0 group-hover:opacity-100">Edit</div>
                                    </button>
                                ))}
                            </div>

                            {habitNames.map((habit, hIdx) => (
                                <div key={`${hIdx}-${habit}`} className="grid grid-cols-[200px_repeat(7,1fr)] border-b border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                    <div className="p-4 flex items-center text-sm font-semibold text-slate-700 dark:text-slate-300 truncate border-r border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-800/20" title={habit}>
                                        {habit}
                                    </div>
                                    {eachDayOfInterval({
                                        start: startOfWeek(currentDate),
                                        end: endOfWeek(currentDate)
                                    }).map(day => {
                                        const dStr = format(day, 'yyyy-MM-dd');
                                        const checks = getDayChecks(dStr);
                                        const isChecked = checks[hIdx];
                                        const isDayToday = isToday(day);

                                        return (
                                            <div key={dStr} className={`p-4 border-l border-slate-100 dark:border-slate-800 flex items-center justify-center ${isDayToday ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}>
