                                                        {isPastDate && count === 0 && (
                                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                                <SpiderWebIcon className="w-full h-full text-red-900/60 dark:text-red-500/60 animate-pulse" strokeWidth={1.5} />
                                                            </div>
                                                        )}
                                                        <span className="relative z-10">{format(d, 'd')}</span>
                                                     </button>
                                                 )
                                            })}
                                        </div>
                                    </div>
                                )
