                                const isCurrentMonth = isSameMonth(day, currentDate);
                                const isTodayDate = isToday(day);
                                const message = getDailyMessage(dStr, count);
                                const isPastDate = isBefore(day, startOfDay(new Date()));

                                return (
                                    <button 
                                        key={dStr} 
                                        onClick={() => onSelectDate(dStr)}
                                        className={`
                                            min-h-[80px] sm:min-h-[112px] p-1 sm:p-2 flex flex-col justify-between items-start transition-colors hover:bg-indigo-50 dark:hover:bg-indigo-900/10 relative group
                                            ${!isCurrentMonth ? 'bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600' : 'bg-white dark:bg-slate-800'}
                                        `}
                                    >
                                        {isPastDate && count === 0 && (
                                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0">
                                                <SpiderWebIcon className="w-12 h-12 sm:w-20 sm:h-20 text-red-900/40 dark:text-red-500/40 animate-pulse" />
                                            </div>
                                        )}
                                        <div className="flex justify-between w-full relative z-10">
                                            <span className={`text-xs sm:text-sm font-semibold w-6 h-6 sm:w-7 sm:h-7 flex items-center justify-center rounded-full ${isTodayDate ? 'bg-indigo-600 text-white' : ''}`}>
