                        <p className="text-slate-500 dark:text-slate-400 text-sm font-medium">{format(parseISO(date), 'EEEE, yyyy')}</p>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                        <XCircleIcon className="w-6 h-6" />
                    </button>
                </div>

                <div className={`px-6 py-3 text-sm font-bold text-center ${messageStyle}`}>
                    {message}
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-3">
                     {habits.map((habit, idx) => (
                         <div key={idx} className="flex items-center gap-3 group">
                             <button 
                                onClick={() => onToggle(idx)}
                                className={`flex-shrink-0 w-8 h-8 rounded-lg border-2 flex items-center justify-center transition-all duration-200 ${
                                    checks[idx] 
                                    ? 'bg-emerald-500 border-emerald-500 text-white' 
                                    : 'border-slate-300 dark:border-slate-600 hover:border-emerald-400 dark:hover:border-emerald-400'
                                }`}
                             >
                                 {checks[idx] && <CheckIcon className="w-5 h-5 stroke-[3]" />}
                             </button>

                             {editingIndex === idx ? (
                                 <input 
                                    type="text" 
                                    value={editValue}
                                    onChange={(e) => setEditValue(e.target.value)}
                                    onBlur={() => { onRename(idx, editValue); setEditingIndex(null); }}
                                    onKeyDown={(e) => { if(e.key === 'Enter') { onRename(idx, editValue); setEditingIndex(null); } }}
                                    autoFocus
                                    className="flex-1 bg-slate-100 dark:bg-slate-800 border-none rounded px-2 py-1 text-sm focus:ring-2 focus:ring-indigo-500"
                                 />
