                                            setEditingIndex(idx);
                                        }
                                    }}
                                 >
                                     {habit}
                                 </span>
                             )}

                             <button 
                                onClick={() => { 
                                    if (!isCustomized) onCustomize();
                                    setEditValue(habit); 
                                    setEditingIndex(idx); 
                                }}
                                className="p-1.5 text-slate-300 hover:text-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity"
                             >
                                 <PencilIcon className="w-4 h-4" />
                             </button>
                         </div>
                     ))}
                </div>

                {isCustomized && (
                    <div className="p-4 border-t border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 flex justify-center">
                        <button onClick={onReset} className="text-xs text-red-500 hover:text-red-600 font-semibold hover:underline">
                            Reset to Global Defaults
                        </button>
                    </div>
                )}
            </div>
        </div>
    );

    return createPortal(content, document.body);
};

