                    const dateStr = format(day, 'yyyy-MM-dd');
                    const checks = getDayChecks(dateStr);
                    const count = checks.filter(Boolean).length;
                    const isCurrentMonth = isSameMonth(day, currentMonth);
                    const isTodayDate = isToday(day);

                    return (
                        <div 
                            key={dateStr}
                            onClick={() => onSelectDate(dateStr)}
                            className={`
                                relative rounded-xl border p-2 flex flex-col justify-between transition-all duration-200 cursor-pointer group min-h-[80px]
                                ${isCurrentMonth ? 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700' : 'bg-slate-50 dark:bg-slate-900/50 border-transparent opacity-50'}
