                            `}
                        >
                            <span className={`text-sm font-semibold ${isTodayDate ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-700 dark:text-slate-300'}`}>
                                {format(day, 'd')}
                            </span>

                            <div className="flex items-end justify-between mt-2">
                                <div className="flex-1 flex gap-0.5 h-1.5 rounded-full overflow-hidden bg-slate-100 dark:bg-slate-700">
                                    <div 
                                        className={`h-full rounded-full ${getScoreColor(count)}`} 
                                        style={{ width: `${(count / MAX_HABITS) * 100}%` }}
                                    ></div>
                                </div>
                                <span className={`text-xs font-bold ml-2 ${getScoreColor(count, false)}`}>{count}</span>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

const ReportsView: React.FC<{
    logs: HabitLog;
    getDayChecks: (date: string) => boolean[];
    onSelectDate: (date: string) => void;
    habitNames: string[];
    dailyConfig: Record<string, string[]>;
}> = ({ logs, habitNames, dailyConfig }) => {
    const habitStats = useMemo(() => {
        const stats = habitNames.map((name, idx) => {
            let count = 0;
            let totalPossible = 0;

            Object.keys(logs).forEach(date => {
                // Simplified: Assuming global habit index mapping
                if (logs[date][idx]) count++;
                totalPossible++; 
            });

            return {
                label: name,
                value: count,
                color: VIBRANT_COLORS[idx % VIBRANT_COLORS.length],
                percentage: totalPossible > 0 ? Math.round((count/totalPossible)*100) : 0
            };
        });
        return stats.sort((a, b) => b.value - a.value);
    }, [logs, habitNames]);

    const totalLogs = Object.keys(logs).length;

    const monthlyTrend = useMemo(() => {
        const last6Months = Array.from({length: 6}).map((_, i) => subMonths(new Date(), 5 - i));
        return last6Months.map(date => {
            const monthStr = format(date, 'yyyy-MM');
            let total = 0;
            let days = 0;

            Object.keys(logs).forEach(d => {
                if (d.startsWith(monthStr)) {
                    total += logs[d].filter(Boolean).length;
                    days++;
                }
            });

            return {
                label: format(date, 'MMM'),
                value: days > 0 ? Math.round(total / days) : 0,
                color: '#6366f1'
            };
        });
    }, [logs]);

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fade-in pb-20">
            <YearlyHeatmap logs={logs} />

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                    <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-6">Habit Performance</h3>
                    <HorizontalBarChart data={habitStats} />
                </div>

                <div className="space-y-8">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                        <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Completion Distribution</h3>
                        <DonutChart data={habitStats.slice(0, 5)} total={Math.max(1, totalLogs * 10)} /> 
                    </div>

                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                         <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Average Daily Score (Last 6 Months)</h3>
                         <VerticalBarGraph data={monthlyTrend} />
                    </div>
                </div>
            </div>
        </div>
    );
};

