                                        <div className="grid grid-cols-7 gap-1">
                                            {mDays.map(d => {
                                                 const dStr = format(d, 'yyyy-MM-dd');
                                                 const count = getDayChecks(dStr).filter(Boolean).length;
                                                 const colorClass = getMonthColor(i, count);
                                                 const isPastDate = isBefore(d, startOfDay(new Date()));

                                                 let textColorClass = '';
                                                 if (count === 0) textColorClass = 'text-slate-300 dark:text-slate-700';
                                                 else if (count <= 6) textColorClass = 'text-slate-900/70'; 
